   117→describe("VisualizationServer", () => {
   118→  let testDir: string;
   119→  let model: Model;
   120→  let server: VisualizationServer;
   121→
   122→  beforeAll(async () => {
   123→    // Use UUID for completely unique directory
   124→    testDir = join(tmpdir(), `dr-test-${randomUUID()}`);
   125→    mkdirSync(testDir, { recursive: true });
   126→    model = await createTestModel(testDir);
   127→    server = new VisualizationServer(model, { authEnabled: false });
   128→  });
   129→
   130→  afterAll(() => {
   131→    server.stop();
   132→    rmSync(testDir, { recursive: true, force: true });
   133→  });
   134→
