     1→/**
     2→ * Unit tests for VisualizationServer
     3→ */
     4→
     5→import { describe, it, expect, beforeAll, afterAll } from "bun:test";
     6→import { Model } from "../../../src/core/model.js";
     7→import { VisualizationServer } from "../../../src/server/server.js";
     8→import { tmpdir } from "os";
     9→import { join } from "path";
    10→import { mkdirSync, rmSync, writeFileSync } from "fs";
    11→import { randomUUID } from "crypto";
    12→
    13→// Test fixture setup
    14→async function createTestModel(rootPath: string): Promise<Model> {
    15→  // Create model directory structure (new documentation-robotics format)
    16→  mkdirSync(join(rootPath, "documentation-robotics", "model", "01_motivation"), {
    17→    recursive: true,
    18→  });
    19→  mkdirSync(join(rootPath, "documentation-robotics", "model", "04_application"), {
    20→    recursive: true,
    21→  });
    22→  mkdirSync(join(rootPath, "documentation-robotics", "model", "05_technology"), {
    23→    recursive: true,
    24→  });
    25→
    26→  // Create manifest.yaml
    27→  const manifestYaml = `version: '0.1.0'
    28→schema: documentation-robotics-v1
    29→cli_version: 0.1.0
    30→created: ${new Date().toISOString()}
    31→updated: ${new Date().toISOString()}
    32→project:
    33→  name: Test Model
    34→  description: Test Description
    35→  version: '0.1.0'
    36→documentation: .dr/README.md
    37→layers:
    38→  motivation:
    39→    order: 1
    40→    name: Motivation
    41→    path: documentation-robotics/model/01_motivation/
    42→    schema: .dr/schemas/01-motivation-layer.schema.json
    43→    enabled: true
    44→  application:
    45→    order: 4
    46→    name: Application
    47→    path: documentation-robotics/model/04_application/
    48→    schema: .dr/schemas/04-application-layer.schema.json
    49→    enabled: true
    50→  technology:
    51→    order: 5
    52→    name: Technology
    53→    path: documentation-robotics/model/05_technology/
    54→    schema: .dr/schemas/05-technology-layer.schema.json
    55→    enabled: true
    56→`;
    57→
    58→  writeFileSync(join(rootPath, "documentation-robotics", "model", "manifest.yaml"), manifestYaml);
    59→
    60→  // Create motivation layer YAML file with both element formats:
    61→  // - test-goal: new-format (hyphenated id, no elementId, no properties)
    62→  // - test-legacy-goal: legacy-format (dotted 3-part id, produces elementId + properties)
    63→  const motivationYaml = `test-goal:
    64→  id: motivation-goal-test-goal
    65→  name: Test Goal
    66→  type: goal
    67→  documentation: A test goal
    68→test-legacy-goal:
    69→  id: motivation.goal.test-legacy-goal
    70→  name: Legacy Test Goal
    71→  type: goal
    72→  documentation: A legacy test goal with semantic ID
    73→  properties:
    74→    priority: high
    75→`;
    76→
    77→  writeFileSync(
    78→    join(rootPath, "documentation-robotics", "model", "01_motivation", "goals.yaml"),
    79→    motivationYaml
    80→  );
    81→
    82→  // Create application layer YAML file with a component that references a technology service
    83→  const applicationYaml = `test-component:
    84→  id: application-component-test-component
    85→  name: Test Component
    86→  type: component
    87→  description: A test component that references a technology service
    88→  references:
    89→    - source: application-component-test-component
    90→      target: technology-service-test-service
    91→      type: uses
    92→`;
    93→
    94→  writeFileSync(
    95→    join(rootPath, "documentation-robotics", "model", "04_application", "components.yaml"),
    96→    applicationYaml
    97→  );
    98→
    99→  // Create technology layer YAML file with a service
   100→  const technologyYaml = `test-service:
   101→  id: technology-service-test-service
   102→  name: Test Service
   103→  type: service
   104→  description: A test service
   105→`;
   106→
   107→  writeFileSync(
   108→    join(rootPath, "documentation-robotics", "model", "05_technology", "services.yaml"),
   109→    technologyYaml
   110→  );
   111→
   112→  // Eager loading required: Visualization server rendering requires all layers
   113→  // to be available for complete UI composition and cross-layer reference display
   114→  return Model.load(rootPath, { lazyLoad: false });
   115→}
   116→
   117→describe("VisualizationServer", () => {
   118→  let testDir: string;
   119→  let model: Model;
   120→  let server: VisualizationServer;
   121→
   122→  beforeAll(async () => {
   123→    // Use UUID for completely unique directory
   124→    testDir = join(tmpdir(), `dr-test-${randomUUID()}`);
   125→    mkdirSync(testDir, { recursive: true });
   126→    model = await createTestModel(testDir);
   127→    server = new VisualizationServer(model, { authEnabled: false });
   128→  });
   129→
   130→  afterAll(() => {
   131→    server.stop();
   132→    rmSync(testDir, { recursive: true, force: true });
   133→  });
   134→
   135→  describe("constructor", () => {
   136→    it("should create a server with a model", () => {
   137→      expect(server).toBeDefined();
   138→      expect(server["model"]).toBe(model);
   139→    });
   140→
   141→    it("should initialize with empty client set", () => {
   142→      expect(server["clients"].size).toBe(0);
   143→    });
   144→
   145→    it("should initialize with empty annotations map", () => {
   146→      expect(server["annotations"].size).toBe(0);
   147→    });
   148→  });
   149→
   150→  describe("serializeModel", () => {
   151→    it("should serialize model with nodes and links", async () => {
   152→      const serialized = await server["serializeModel"]();
   153→
   154→      expect(serialized).toHaveProperty("nodes");
   155→      expect(serialized).toHaveProperty("links");
   156→      expect(Array.isArray(serialized.nodes)).toBe(true);
   157→      expect(Array.isArray(serialized.links)).toBe(true);
   158→    });
   159→
   160→    it("should include all elements as nodes", async () => {
   161→      const serialized = await server["serializeModel"]();
   162→
   163→      expect(serialized.nodes.length).toBeGreaterThan(0);
   164→    });
   165→
   166→    it("should include required fields on each node", async () => {
   167→      const serialized = await server["serializeModel"]();
   168→
   169→      const node = serialized.nodes[0];
   170→      expect(node).toHaveProperty("id");
   171→      expect(node).toHaveProperty("spec_node_id");
   172→      expect(node).toHaveProperty("type");
   173→      expect(node).toHaveProperty("layer_id");
   174→      expect(node).toHaveProperty("name");
   175→    });
   176→
   177→    it("should not embed annotations directly on serialized nodes", async () => {
   178→      const serialized = await server["serializeModel"]();
   179→
   180→      // Annotations are stored server-side in the annotations map, not on serialized nodes
   181→      for (const node of serialized.nodes) {
   182→        expect(node).not.toHaveProperty("annotations");
   183→      }
   184→    });
   185→
   186→    it("should tag nodes with correct layer_id", async () => {
   187→      const serialized = await server["serializeModel"]();
   188→
   189→      const motivationNodes = serialized.nodes.filter((n: any) => n.layer_id === "motivation");
   190→      expect(motivationNodes.length).toBeGreaterThan(0);
   191→    });
   192→
   193→    it("should include elementId for legacy-format elements with semantic IDs", async () => {
   194→      const serialized = await server["serializeModel"]();
   195→
   196→      const legacyNode = serialized.nodes.find(
   197→        (n: any) => n.elementId === "motivation.goal.test-legacy-goal"
   198→      );
   199→      expect(legacyNode).toBeDefined();
   200→      expect(legacyNode.elementId).toBe("motivation.goal.test-legacy-goal");
   201→    });
   202→
   203→    it("should omit elementId for new-format elements without semantic IDs", async () => {
   204→      const serialized = await server["serializeModel"]();
   205→
   206→      const newFormatNode = serialized.nodes.find((n: any) => n.name === "Test Goal");
   207→      expect(newFormatNode).toBeDefined();
   208→      expect(newFormatNode).not.toHaveProperty("elementId");
   209→    });
   210→
   211→    it("should include properties when non-empty", async () => {
   212→      const serialized = await server["serializeModel"]();
   213→
   214→      const legacyNode = serialized.nodes.find(
   215→        (n: any) => n.elementId === "motivation.goal.test-legacy-goal"
   216→      );
   217→      expect(legacyNode).toBeDefined();
   218→      expect(legacyNode).toHaveProperty("properties");
   219→      expect(legacyNode.properties.priority).toBe("high");
   220→    });
   221→
   222→    it("should omit properties when empty", async () => {
   223→      const serialized = await server["serializeModel"]();
   224→
   225→      const newFormatNode = serialized.nodes.find((n: any) => n.name === "Test Goal");
   226→      expect(newFormatNode).toBeDefined();
   227→      expect(newFormatNode).not.toHaveProperty("properties");
   228→    });
   229→
   230→    it("should include source_layer_id and target_layer_id on cross-layer reference links", async () => {
   231→      const serialized = await server["serializeModel"]();
   232→
   233→      // Find the cross-layer reference link from application component to technology service
   234→      const refLink = serialized.links.find(
   235→        (l: any) =>
   236→          l.id.startsWith("ref:") &&
   237→          l.source === "application-component-test-component" &&
   238→          l.target === "technology-service-test-service"
   239→      );
   240→
   241→      expect(refLink).toBeDefined();
   242→      expect(refLink.source_layer_id).toBe("application");
   243→      expect(refLink.target_layer_id).toBe("technology");
   244→      expect(refLink.id).toMatch(/^ref:/);
   245→      expect(refLink.type).toBe("uses");
   246→    });
   247→  });
   248→
