      for (const rel of e.relationships) {
        const linkId = `rel:${rel.source}:${rel.target}:${rel.predicate}`;
        if (!linksMap.has(linkId)) {
          linksMap.set(linkId, {
            id: linkId,
            source: rel.source,
            target: rel.target,
            type: rel.predicate,
            layer_id: layerId,
