    13→// Test fixture setup
    14→async function createTestModel(rootPath: string): Promise<Model> {
    15→  // Create model directory structure (new documentation-robotics format)
    16→  mkdirSync(join(rootPath, "documentation-robotics", "model", "01_motivation"), {
