  1442→  private async serializeModel(): Promise<any> {
  1443→    const nodes: any[] = [];
  1444→    const linksMap = new Map<string, any>();
  1445→
  1446→    // Build element-id → layer_id lookup so cross-layer reference links can
  1447→    // carry accurate source_layer_id / target_layer_id even when the
  1448→    // referenced element lives in a different layer.
  1449→    const elementLayerMap = new Map<string, string>();
  1450→    for (const [layerName, layer] of this.model.layers) {
  1451→      for (const e of layer.listElements()) {
  1452→        const layerId = e.layer_id || layerName;
  1453→        if (e.id) elementLayerMap.set(e.id, layerId);
  1454→      }
  1455→    }
  1456→
  1457→    for (const [layerName, layer] of this.model.layers) {
  1458→      for (const e of layer.listElements()) {
  1459→        const layerId = e.layer_id || layerName;
  1460→
  1461→        // Node — all model fields for complete client-side access
  1462→        const node: any = {
  1463→          id: e.id,
  1464→          spec_node_id: e.spec_node_id,
  1465→          type: e.type,
  1466→          layer_id: layerId,
  1467→          name: e.name,
  1468→        };
  1469→        if (e.description) node.description = e.description;
  1470→        if (e.attributes && Object.keys(e.attributes).length > 0) node.attributes = e.attributes;
  1471→        if (e.source_reference) node.source_reference = e.source_reference;
  1472→        if (e.metadata) node.metadata = e.metadata;
  1473→
  1474→        // Legacy format support: detect semantic IDs (3-part dotted format)
  1475→        // and include elementId and properties fields for backward compatibility
  1476→        if (e.id && e.id.includes('.')) {
  1477→          const parts = e.id.split('.');
  1478→          // Semantic ID format: {layer}.{type}.{name}
  1479→          if (parts.length === 3) {
  1480→            node.elementId = e.id;
  1481→          }
  1482→        }
  1483→
  1484→        // Include properties as alias for attributes when non-empty (backward compatibility)
  1485→        if (e.attributes && Object.keys(e.attributes).length > 0) {
  1486→          node.properties = e.attributes;
  1487→        }
  1488→
  1489→        nodes.push(node);
  1490→
  1491→        // Intra-layer links from relationships
  1492→        for (const rel of e.relationships) {
  1493→          const linkId = `rel:${rel.source}:${rel.target}:${rel.predicate}`;
  1494→          if (!linksMap.has(linkId)) {
  1495→            linksMap.set(linkId, {
  1496→              id: linkId,
  1497→              source: rel.source,
  1498→              target: rel.target,
  1499→              type: rel.predicate,
  1500→              layer_id: layerId,
  1501→            });
  1502→          }
  1503→        }
  1504→
  1505→        // Cross-layer links from references
  1506→        for (const ref of e.references) {
  1507→          const linkId = `ref:${ref.source}:${ref.target}:${ref.type}`;
  1508→          if (!linksMap.has(linkId)) {
  1509→            linksMap.set(linkId, {
  1510→              id: linkId,
  1511→              source: ref.source,
  1512→              target: ref.target,
  1513→              type: ref.type,
  1514→              source_layer_id: elementLayerMap.get(ref.source) || layerId,
  1515→              target_layer_id: elementLayerMap.get(ref.target) || 'unknown',
  1516→            });
  1517→          }
  1518→        }
  1519→      }
