    // Create annotation
    const createAnnotationRoute = createRoute({
      method: 'post',
      path: '/api/annotations',
      tags: ['Annotations'],
      summary: 'Create annotation',
      description: 'Create a new annotation on a model element',
      security: [{ bearerAuth: [] }],
      request: {
        body: {
