    // OpenAPI documentation endpoint
    // Note: @hono/zod-openapi always generates 3.1.0, so we specify it here
    // but the version is normalized to 3.0.3 in the generate-openapi.ts script
    this.app.doc('/api-spec.yaml', {
      openapi: '3.1.0',
