      font-size: 13px;
    }

    .element-item:hover {
      background: #f0f0f0;
      border-left-color: #2196F3;
    }

    .element-item.selected {
      background: #e3f2fd;
      border-left-color: #2196F3;
      font-weight: 500;
    }

    .element-details {
      min-height: 300px;
