    }

    .annotation-item .author {
      font-weight: 600;
      color: #666;
    }

    .annotation-item .text {
      margin: 4px 0 0 0;
      color: #333;
    }

    .annotation-item .timestamp {
      font-size: 11px;
      color: #999;
      margin-top: 4px;
    }

    .annotation-form {
      display: grid;
      gap: 8px;
      margin-top: 12px;
    }

    .annotation-form input,
    .annotation-form textarea {
      padding: 8px;
